declare(strict_types=1);
require_once dirname(__DIR__, 2) . '/config/runtime.php';
sds_session_start();
define('SDS_PERPUSTAKAAN_APP', true);
$root = dirname(__DIR__, 2);
require_once $root . '/db.php';
require_once $root . '/config/perpus.php';
try { sds_perpus_ensure_schema($conn); } catch (Throwable $e) { error_log('[OPAC startup] ' . $e->getMessage()); }

function opac_h($v): string { return htmlspecialchars((string)$v, ENT_QUOTES, 'UTF-8'); }
function opac_has_cover($value): bool
{
    $name = basename(trim((string)$value));
    return $name !== '' && is_file(sds_root_path('uploads/perpus/buku/' . $name));
}
$school=['nama_sekolah'=>'Sekolah','logo'=>''];
$r=$conn->query('SELECT nama_sekolah,logo FROM pengaturan LIMIT 1');if($r&&($x=$r->fetch_assoc()))$school=array_merge($school,$x);
$settings=[];
if(sds_perpus_table_exists($conn,'perpus_pengaturan')){$r=$conn->query('SELECT kode,nilai FROM perpus_pengaturan');while($r&&($x=$r->fetch_assoc()))$settings[$x['kode']]=$x['nilai'];}
$opacActive=($settings['opac_aktif']??'1')==='1';$reservationActive=($settings['reservasi_aktif']??'1')==='1';
$title=trim((string)($settings['opac_judul']??'Katalog Perpustakaan'))?:'Katalog Perpustakaan';
$base=sds_base_url('perpustakaan/opac/');$adminBase=sds_base_url('perpustakaan/');
$logo=!empty($school['logo'])?sds_base_url('uploads/logo/'.rawurlencode(basename((string)$school['logo']))):'';
if(!$opacActive){http_response_code(503);?><!doctype html><html lang="id"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><link rel="stylesheet" href="assets/opac.css?v=2.6.1"><title>OPAC Nonaktif</title></head><body><main class="opac-maintenance"><div><h1>OPAC sedang dinonaktifkan</h1><p>Silakan menghubungi petugas Perpustakaan.</p></div></main><script>document.querySelectorAll(".opac-cover img,.opac-popular-grid img,.opac-detail-cover img").forEach(function(img){function fallback(){img.remove()}if(img.complete&&img.naturalWidth===0)fallback();else img.addEventListener("error",fallback,{once:true})});</script></body></html><?php exit;}
if(!sds_perpus_table_exists($conn,'perpus_buku')){http_response_code(503);exit('Modul Perpustakaan belum diinisialisasi.');}
$categories=[];$r=$conn->query('SELECT id,nama FROM perpus_kategori_buku WHERE status_aktif=1 ORDER BY nama');while($r&&($x=$r->fetch_assoc()))$categories[]=$x;
$types=[];$r=$conn->query('SELECT id,nama FROM perpus_tipe_koleksi ORDER BY nama');while($r&&($x=$r->fetch_assoc()))$types[]=$x;
$q=trim((string)($_GET['q']??''));$category=(int)($_GET['kategori']??0);$collection=(int)($_GET['tipe']??0);$year=trim((string)($_GET['tahun']??''));$available=!empty($_GET['tersedia']);$detailId=(int)($_GET['id']??0);
$bookDetail=null;$detailCopies=[];
if($detailId>0){
 $stmt=$conn->prepare("SELECT b.*,kb.nama kategori,tk.nama tipe,g.nama gmd,COALESCE(NULLIF(p.nama,''),b.penerbit_teks) penerbit,(SELECT GROUP_CONCAT(pa.nama ORDER BY pa.nama SEPARATOR '; ') FROM perpus_buku_pengarang bp JOIN perpus_pengarang pa ON pa.id=bp.pengarang_id WHERE bp.buku_id=b.id) pengarang,(SELECT GROUP_CONCAT(s.nama ORDER BY s.nama SEPARATOR '; ') FROM perpus_buku_subyek bs JOIN perpus_subyek s ON s.id=bs.subyek_id WHERE bs.buku_id=b.id) subyek FROM perpus_buku b LEFT JOIN perpus_kategori_buku kb ON kb.id=b.kategori_id LEFT JOIN perpus_tipe_koleksi tk ON tk.id=b.tipe_koleksi_id LEFT JOIN perpus_gmd g ON g.id=b.gmd_id LEFT JOIN perpus_penerbit p ON p.id=b.penerbit_id WHERE b.id=? AND b.status_opac=1 LIMIT 1");
 $stmt->bind_param('i',$detailId);$stmt->execute();$bookDetail=$stmt->get_result()->fetch_assoc();$stmt->close();
 if($bookDetail){$stmt=$conn->prepare("SELECT barcode,nomor_inventaris,lokasi_rak,kondisi_fisik,status FROM perpus_buku_eksemplar WHERE buku_id=? AND status<>'nonaktif' ORDER BY barcode");$stmt->bind_param('i',$detailId);$stmt->execute();$rr=$stmt->get_result();while($rr&&($x=$rr->fetch_assoc()))$detailCopies[]=$x;$stmt->close();}
}
$conditions=['b.status_opac=1'];$params=[];$typesBind='';
if($q!==''){$conditions[]="(b.judul LIKE ? OR b.isbn LIKE ? OR b.penerbit_teks LIKE ? OR EXISTS(SELECT 1 FROM perpus_buku_pengarang bp JOIN perpus_pengarang pa ON pa.id=bp.pengarang_id WHERE bp.buku_id=b.id AND pa.nama LIKE ?) OR EXISTS(SELECT 1 FROM perpus_buku_subyek bs JOIN perpus_subyek sy ON sy.id=bs.subyek_id WHERE bs.buku_id=b.id AND sy.nama LIKE ?))";$like='%'.$q.'%';for($i=0;$i<5;$i++){$params[]=$like;$typesBind.='s';}}
if($category>0){$conditions[]='b.kategori_id=?';$params[]=$category;$typesBind.='i';}
if($collection>0){$conditions[]='b.tipe_koleksi_id=?';$params[]=$collection;$typesBind.='i';}
if($year!==''){$conditions[]='b.tahun_terbit=?';$params[]=$year;$typesBind.='s';}
if($available){$conditions[]="EXISTS(SELECT 1 FROM perpus_buku_eksemplar av WHERE av.buku_id=b.id AND av.status='tersedia')";}
$where=implode(' AND ',$conditions);$page=max(1,(int)($_GET['p']??1));$perPage=12;$offset=($page-1)*$perPage;
$countSql="SELECT COUNT(*) total FROM perpus_buku b WHERE $where";$stmt=$conn->prepare($countSql);if($params)$stmt->bind_param($typesBind,...$params);$stmt->execute();$total=(int)($stmt->get_result()->fetch_assoc()['total']??0);$stmt->close();$pages=max(1,(int)ceil($total/$perPage));if($page>$pages){$page=$pages;$offset=($page-1)*$perPage;}
$listSql="SELECT b.id,b.judul,b.isbn,b.tahun_terbit,b.nomor_panggil,b.sampul,kb.nama kategori,tk.nama tipe,COALESCE(NULLIF(p.nama,''),b.penerbit_teks) penerbit,(SELECT GROUP_CONCAT(pa.nama ORDER BY pa.nama SEPARATOR '; ') FROM perpus_buku_pengarang bp JOIN perpus_pengarang pa ON pa.id=bp.pengarang_id WHERE bp.buku_id=b.id) pengarang,(SELECT COUNT(*) FROM perpus_buku_eksemplar e WHERE e.buku_id=b.id AND e.status<>'nonaktif') jumlah,(SELECT COUNT(*) FROM perpus_buku_eksemplar e WHERE e.buku_id=b.id AND e.status='tersedia') tersedia,(SELECT COUNT(*) FROM perpus_peminjaman_detail pd WHERE pd.buku_id=b.id) dipinjam_total FROM perpus_buku b LEFT JOIN perpus_kategori_buku kb ON kb.id=b.kategori_id LEFT JOIN perpus_tipe_koleksi tk ON tk.id=b.tipe_koleksi_id LEFT JOIN perpus_penerbit p ON p.id=b.penerbit_id WHERE $where ORDER BY b.updated_at DESC,b.judul LIMIT ? OFFSET ?";
$stmt=$conn->prepare($listSql);$listParams=$params;$listTypes=$typesBind.'ii';$listParams[]=$perPage;$listParams[]=$offset;$stmt->bind_param($listTypes,...$listParams);$stmt->execute();$books=[];$rr=$stmt->get_result();while($rr&&($x=$rr->fetch_assoc()))$books[]=$x;$stmt->close();
$popular=[];if(($settings['opac_tampilkan_populer']??'1')==='1'&&!$q&&!$category&&!$collection&&!$year&&!$available){$r=$conn->query("SELECT b.id,b.judul,b.sampul,b.tahun_terbit,COUNT(pd.id) total FROM perpus_buku b JOIN perpus_peminjaman_detail pd ON pd.buku_id=b.id WHERE b.status_opac=1 GROUP BY b.id,b.judul,b.sampul,b.tahun_terbit ORDER BY total DESC,b.judul LIMIT 6");while($r&&($x=$r->fetch_assoc()))$popular[]=$x;}
$queryBase=$_GET;unset($queryBase['p'],$queryBase['id']);
