?></b></div><?php endforeach;endif;?></div></section><?php else:?>
<?php if($popular):?><section class="opac-popular"><div class="opac-section-title"><div><small>Paling diminati</small><h2>Koleksi Populer</h2></div></div><div class="opac-popular-grid"><?php foreach($popular as $p):?><a href="?id=<?=(int)$p['id']?>"><div><?php if(opac_has_cover($p['sampul'])):?><img src="<?=opac_h(sds_base_url('uploads/perpus/buku/'.rawurlencode(basename((string)$p['sampul']))))?>" alt=""><?php else:?><span>📖</span><?php endif;?></div><strong><?=opac_h($p['judul'])?></strong><small><?=opac_h($p['tahun_terbit']?:'')?> · <?=number_format((int)$p['total'],0,',','.')?> kali dipinjam</small></a><?php endforeach;?></div></section><?php endif;?>
<section class="opac-catalog"><aside><form method="get"><h3>Filter Katalog</h3><label>Kata kunci<input name="q" value="<?=opac_h($q)?>"></label><label>Kategori<select name="kategori"><option value="0">Semua kategori</option><?php foreach($categories as $c):?><option value="<?=(int)$c['id']?>" <?=$category===(int)$c['id']?'selected':''?>><?=opac_h($c['nama'])?></option><?php endforeach;?></select></label><label>Tipe koleksi<select name="tipe"><option value="0">Semua tipe</option><?php foreach($types as $t):?><option value="<?=(int)$t['id']?>" <?=$collection===(int)$t['id']?'selected':''?>><?=opac_h($t['nama'])?></option><?php endforeach;?></select></label><label>Tahun terbit<input name="tahun" value="<?=opac_h($year)?>" inputmode="numeric" maxlength="9"></label><label class="opac-check"><input type="checkbox" name="tersedia" value="1" <?=$available?'checked':''?>> Hanya yang tersedia</label><button>Terapkan Filter</button><a href="<?=$base?>">Reset</a></form></aside><div class="opac-results"><div class="opac-section-title"><div><small><?=number_format($total,0,',','.')?> hasil</small><h2><?= $q!==''?'Hasil pencarian “'.opac_h($q).'”':'Semua Koleksi' ?></h2></div></div><?php if(!$books):?><div class="opac-empty"><span>🔎</span><h3>Koleksi tidak ditemukan</h3><p>Coba gunakan kata kunci atau filter yang berbeda.</p></div><?php else:?><div class="opac-book-grid"><?php foreach($books as $b):?><article class="opac-book"><a class="opac-cover" href="?id=<?=(int)$b['id']?>"><?php if(opac_has_cover($b['sampul'])):?><img src="<?=opac_h(sds_base_url('uploads/perpus/buku/'.rawurlencode(basename((string)$b['sampul']))))?>" alt="Sampul <?=opac_h($b['judul'])?>"><?php else:?><span>📖</span><?php endif;?><em class="<?=$b['tersedia']>0?'available':'unavailable'?>"><?=$b['tersedia']>0?'Tersedia':'Tidak tersedia'?></em></a><div class="opac-book-body"><small><?=opac_h($b['kategori']?:$b['tipe']?:'Koleksi')?></small><h3><a href="?id=<?=(int)$b['id']?>"><?=opac_h($b['judul'])?></a></h3><p><?=opac_h($b['pengarang']?:'Pengarang tidak dicantumkan')?></p><div><span><?=opac_h($b['tahun_terbit']?:'-')?></span><span><?=number_format((int)$b['tersedia'],0,',','.')?>/<?=number_format((int)$b['jumlah'],0,',','.')?> tersedia</span></div></div></article><?php endforeach;?></div><?php endif;?><?php if($pages>1):?><nav class="opac-pagination"><?php for($i=1;$i<=$pages;$i++):$queryBase['p']=$i;?><a class="<?=$i===$page?'active':''?>" href="?<?=opac_h(http_build_query($queryBase))?>"><?=$i?></a><?php endfor;?></nav><?php endif;?></div></section><?php endif;?>
